const t = $input.first().json;

// HTML-Tags entfernen
const stripHtml = s => (s || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();

const question = stripHtml(t.question).slice(0, 2000);
const solution = stripHtml(t.solution).slice(0, 2000);
const subject = stripHtml(t.subject);

// Kombinierter Text für Embedding
const combinedText = `${subject}\n\nFrage:\n${question}\n\nLösung:\n${solution}`;

return [{
  json: {
    id: t.id,
    number: t.number,
    subject: subject,
    question: question,
    solution: solution,
    combinedText: combinedText,
    closedAt: t.closed
  }
}];

